id m03b010_async_call(void) async;
id m03b010_main_only(id seed) __attribute__((objc_executor(main)));

id m03b010_positive(id seed) async __attribute__((objc_executor(main))) {
    id value = await m03b010_async_call();
    return m03b010_main_only(seed);
}

id m03b010_negative(id seed) async __attribute__((objc_executor(global))) {
    id value = m03b010_main_only(seed);
    return value;
}
